SELECT AVG(accuracy) AS average_accuracy
FROM interaction_metrics
WHERE session_id = 0;

SELECT COUNT(interaction_id) AS interaction_count
FROM game_object_interactions
WHERE interaction_type = 'click';

SELECT session_id
FROM interaction_metrics
WHERE accuracy = (SELECT MAX(accuracy) FROM interaction_metrics);

SELECT accuracy
FROM interaction_metrics
WHERE metric_id = 1;
